#include <stdio.h>
#include <stdlib.h>
#include <float.h>
#include <math.h>
#include <omp.h>
#include "kmeans.h"

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

void kmeans_kernel_c(float *feature,   
                     float *clusters,
                     int *membership,
                     int npoints,
                     int nclusters,
                     int nfeatures) 
{
    #pragma omp parallel for schedule(static)
    for (int point_id = 0; point_id < npoints; point_id++)
    {
        int index = 0;
        float min_dist = FLT_MAX;

        for (int i = 0; i < nclusters; i++) {
            float dist = 0;
            for (int l = 0; l < nfeatures; l++) {
                float diff = feature[l * npoints + point_id] - clusters[i * nfeatures + l];
                dist += diff * diff;
            }

            if (dist < min_dist) {
                min_dist = dist;
                index = i;
            }
        }

        membership[point_id] = index;
    }
}

void kmeans_swap(float *feature,   
                 float *feature_swap,
                 int npoints,
                 int nfeatures)
{
    #pragma omp parallel for schedule(static)
    for (int tid = 0; tid < npoints; tid++) {
        for (int i = 0; i < nfeatures; i++) {
            feature_swap[i * npoints + tid] = feature[tid * nfeatures + i];
        }
    }
}

int kmeansOCL(float **feature,    
              int n_features,
              int n_points,
              int n_clusters,
              int *membership,
              float **clusters,
              int *new_centers_len,
              float **new_centers)
{
    int delta = 0;
    int i, j, k;

    float *feature_swap = (float*)malloc(n_points * n_features * sizeof(float));
    if (!feature_swap) {
        printf("ERROR: malloc failed\n");
        return -1;
    }

    int *membership_OCL = (int*)malloc(n_points * sizeof(int));
    if (!membership_OCL) {
        printf("ERROR: malloc failed\n");
        free(feature_swap);
        return -1;
    }

    kmeans_swap(feature[0], feature_swap, n_points, n_features);

    float *cluster_flat = (float*)malloc(n_clusters * n_features * sizeof(float));
    if (!cluster_flat) {
        printf("ERROR: malloc failed\n");
        free(feature_swap);
        free(membership_OCL);
        return -1;
    }

    for (i = 0; i < n_clusters; i++) {
        for (j = 0; j < n_features; j++) {
            cluster_flat[i * n_features + j] = clusters[i][j];
        }
    }

    kmeans_kernel_c(feature_swap, cluster_flat, membership_OCL, n_points, n_clusters, n_features);

    delta = 0;
    for (i = 0; i < n_points; i++)
    {
        int cluster_id = membership_OCL[i];
        new_centers_len[cluster_id]++;
        if (membership_OCL[i] != membership[i])
        {
            delta++;
            membership[i] = membership_OCL[i];
        }
        for (j = 0; j < n_features; j++)
        {
            new_centers[cluster_id][j] += feature[i][j];
        }
    }

    free(feature_swap);
    free(membership_OCL);
    free(cluster_flat);

    return delta;
}

float **kmeans_clustering_openmp(float **feature,    
                                 int nfeatures,
                                 int npoints,
                                 int nclusters,
                                 float threshold,
                                 int *membership) 
{    
    int i, j, n = 0;				
    int loop = 0, temp;
    int *new_centers_len;	
    float delta;				
    float **clusters;			
    float **new_centers;		

    int *initial;				
    int initial_points;
    int c = 0;

    if (nclusters > npoints)
        nclusters = npoints;

    clusters = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*) malloc(nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    initial = (int *) malloc (npoints * sizeof(int));
    for (i = 0; i < npoints; i++)
    {
        initial[i] = i;
    }
    initial_points = npoints;

    for (i = 0; i < nclusters && initial_points >= 0; i++) {
        for (j = 0; j < nfeatures; j++)
            clusters[i][j] = feature[initial[n]][j];	

        temp = initial[n];
        initial[n] = initial[initial_points-1];
        initial[initial_points-1] = temp;
        initial_points--;
        n++;
    }

    for (i = 0; i < npoints; i++)
        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));

    new_centers = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*) calloc(nclusters * nfeatures, sizeof(float));
    for (i = 1; i < nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    do {
        delta = 0.0;

        delta = (float) kmeansOCL(feature,
                                  nfeatures,		
                                  npoints,			
                                  nclusters,		
                                  membership,		
                                  clusters,		
                                  new_centers_len,	
                                  new_centers		
                                  );

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];	
                new_centers[i][j] = 0.0;	
            }
            new_centers_len[i] = 0;			
        }	 
        c++;
    } while ((delta > threshold) && (loop++ < 500));	
    printf("iterated %d times\n", c);
    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}

int cluster_openmp(int numObjects,      
                   int numAttributes,   
                   float **attributes,                  
                   int nclusters,
                   float threshold,       
                   float ***cluster_centres)
{
    int *membership;
    float **tmp_cluster_centres;

    membership = (int*) malloc(numObjects * sizeof(int));

    srand(7);

    tmp_cluster_centres = kmeans_clustering_openmp(attributes,
                                                   numAttributes,
                                                   numObjects,
                                                   nclusters,
                                                   threshold,
                                                   membership);      

    if (*cluster_centres) {
        free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    free(membership);

    return 0;
}
